+import React, { useRef, useEffect, useState, useMemo } from 'react';
+
+// Room colors for minimap
+const MINIMAP_ROOM_COLORS: Record<string, string> = {
+  throne: '#FFD700',    // gold
+  workshop: '#FFA500',  // orange
+  library: '#0000FF',   // blue
+  warroom: '#FF0000',   // red
+  healing: '#008000',   // green
+  watchtower: '#808080',// gray
+  scribe: '#A52A2A',    // brown
+  dungeon: '#2F4F4F',   // dark gray
+  greathall: '#800080', // purple
+};
+
+// Map tier/label to minimap room keys
+const MINIMAP_ROOM_KEYS: Record<string, string> = {
+  king: 'throne',
+  squire: 'workshop',
+  scribe: 'scribe',
+  knight: 'warroom',
+  healer: 'healing',
+  sentinel: 'watchtower',
+  judge: 'dungeon',
+  nobility: 'library',
+  blacksmith: 'greathall',
+};
+
+function Minimap({ agents }: { agents: AgentInfo[] }) {
+  const canvasRef = useRef<HTMLCanvasElement>(null);
+
+  // Dimensions
+  const width = 160;
+  const height = 120;
+  const padding = 8;
+  const cols = 3;
+  const rows = 3;
+  const roomW = (width - padding * (cols + 1)) / cols;
+  const roomH = (height - padding * (rows + 1)) / rows;
+
+  // Compute agents grouped by minimap room key
+  const agentsByRoom = useMemo(() => {
+    const map = new Map<string, AgentInfo[]>();
+    for (const a of agents) {
+      const key = MINIMAP_ROOM_KEYS[a.tier];
+      if (!key) continue;
+      const list = map.get(key) ?? [];
+      list.push(a);
+      map.set(key, list);
+    }
+    return map;
+  }, [agents]);
+
+  // Draw minimap on canvas
+  useEffect(() => {
+    const canvas = canvasRef.current;
+    if (!canvas) return;
+    const ctx = canvas.getContext('2d');
+    if (!ctx) return;
+
+    // Clear and draw background with semi-transparent overlay
+    ctx.clearRect(0, 0, width, height);
+    ctx.fillStyle = 'rgba(20, 20, 20, 0.85)';
+    ctx.fillRect(0, 0, width, height);
+
+    // Draw rooms as rectangles
+    // Map room keys to grid positions (col,row)
+    const roomPositions: Record<string, { col: number; row: number }> = {
+      throne: { col: 1, row: 0 },
+      library: { col: 0, row: 1 },
+      warroom: { col: 1, row: 1 },
+      watchtower: { col: 2, row: 1 },
+      workshop: { col: 0, row: 2 },
+      healing: { col: 1, row: 2 },
+      scribe: { col: 0, row: 3 }, // but row 3 is outside 3 rows, so clamp to 2
+      dungeon: { col: 1, row: 3 }, // clamp to 2
+      greathall: { col: 2, row: 2 },
+    };
+
+    // Adjust scribe and dungeon rows to fit 3 rows max (0-based)
+    roomPositions.scribe.row = 2;
+    roomPositions.dungeon.row = 2;
+
+    // Draw each room rectangle
+    for (const [key, pos] of Object.entries(roomPositions)) {
+      const x = padding + pos.col * (roomW + padding);
+      const y = padding + pos.row * (roomH + padding);
+      const color = MINIMAP_ROOM_COLORS[key] ?? '#444';
+
+      // Room background rectangle
+      ctx.fillStyle = color;
+      ctx.globalAlpha = 0.3;
+      ctx.fillRect(x, y, roomW, roomH);
+      ctx.globalAlpha = 1.0;
+
+      // Room border
+      ctx.strokeStyle = color;
+      ctx.lineWidth = 1.5;
+      ctx.strokeRect(x, y, roomW, roomH);
+
+      // Draw agent dots inside room
+      const agentsInRoom = agentsByRoom.get(key) ?? [];
+      const dotRadius = 4;
+      const spacing = 10;
+      const maxDotsPerRow = Math.floor(roomW / spacing);
+      agentsInRoom.forEach((agent, i) => {
+        const dotX = x + spacing / 2 + (i % maxDotsPerRow) * spacing;
+        const dotY = y + roomH - spacing / 2 - Math.floor(i / maxDotsPerRow) * spacing;
+        // Dot color: use tier color from main COLORS or fallback
+        let dotColor = '#fff';
+        switch (agent.tier) {
+          case 'king': dotColor = '#FFD700'; break;       // gold
+          case 'squire': dotColor = '#FFA500'; break;     // orange
+          case 'nobility': dotColor = '#0000FF'; break;   // blue
+          case 'knight': dotColor = '#FF0000'; break;     // red
+          case 'healer': dotColor = '#008000'; break;     // green
+          case 'sentinel': dotColor = '#808080'; break;   // gray
+          case 'scribe': dotColor = '#A52A2A'; break;     // brown
+          case 'judge': dotColor = '#2F4F4F'; break;      // dark gray
+          case 'blacksmith': dotColor = '#800080'; break; // purple
+          default: dotColor = '#fff'; break;
+        }
+        ctx.beginPath();
+        ctx.fillStyle = dotColor;
+        ctx.shadowColor = 'rgba(0,0,0,0.6)';
+        ctx.shadowBlur = 2;
+        ctx.shadowOffsetX = 1;
+        ctx.shadowOffsetY = 1;
+        ctx.arc(dotX, dotY, dotRadius, 0, Math.PI * 2);
+        ctx.fill();
+        ctx.shadowBlur = 0;
+        ctx.shadowOffsetX = 0;
+        ctx.shadowOffsetY = 0;
+      });
+    }
+  }, [agents, agentsByRoom, height, padding, roomH, roomW, width]);
+
+  return (
+    <canvas
+      ref={canvasRef}
+      width={width}
+      height={height}
+      style={{
+        position: 'absolute',
+        top: 10,
+        right: 10,
+        width: width,
+        height: height,
+        borderRadius: 6,
+        pointerEvents: 'none',
+        userSelect: 'none',
+        zIndex: 1000,
+        boxShadow: '0 0 8px rgba(0,0,0,0.8)',
+      }}
+      aria-label="Minimap overview panel"
+    />
+  );
+}
